const body = $input.first()?.json?.body || {};
const action = body.action || 'log';
let query = '';
let params = [];

if (action === 'log') {
  query = 'INSERT INTO gda_ai_feedback (source, recommendation_id, recommendation_text, user_action, user_note, modified_text) VALUES ($1, $2, $3, $4, $5, $6) RETURNING id, source, user_action, created_at';
  params = [body.source||'unknown', body.recommendation_id||'', body.recommendation_text||'', body.user_action||'accept', body.user_note||'', body.modified_text||''];
} else if (action === 'get') {
  if (body.source) {
    query = 'SELECT * FROM gda_ai_feedback WHERE source = $1 ORDER BY created_at DESC LIMIT 20';
    params = [body.source];
  } else {
    query = 'SELECT * FROM gda_ai_feedback ORDER BY created_at DESC LIMIT 20';
    params = [];
  }
} else if (action === 'stats') {
  query = 'SELECT source, user_action, COUNT(*) as cnt FROM gda_ai_feedback GROUP BY source, user_action ORDER BY source, cnt DESC';
  params = [];
} else {
  query = 'SELECT 1 as ok';
  params = [];
}
return [{json: {action, query, params}}];

if (!$env.GDA_API_KEY_2026 || !$env.GDA_DEPLOY_KEY_2026 || !$env.GDA_WEBHOOK_SECRET_2026) throw new Error('2026 auth env vars not set');
const headers = $input.first().json.headers || {};
const body = $input.first().json.body || {};
const auth = headers["x-gda-auth"] || headers["x-gda-key"] || body.auth_key || body.deploy_key || "";
const validKeys = [$env.GDA_DEPLOY_KEY_2026, $env.GDA_API_KEY_2026, $env.GDA_WEBHOOK_SECRET_2026];
if (!validKeys.includes(auth)) {
  const origin = (headers.origin || headers.referer || "").toLowerCase();
  const trusted = ["gda.csr-llc.tech","n8n.csr-llc.tech","localhost","gdacommand.retool.com"];
  if (!trusted.some(o => origin.includes(o))) throw new Error("Unauthorized");
}
return [{ json: body }];
